import { Component, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ActivatedRoute, Router, RouterModule } from '@angular/router';
import { FormsModule } from '@angular/forms';
import { AppStoreService } from '../../services/app-store.service';
import { ReviewService } from '../../services/review.service';
import { AppDefinition, AppReview } from '../../models/app-store.models';
import { Observable, switchMap, of, catchError, tap, shareReplay } from 'rxjs';
import { ButtonModule } from 'primeng/button';
import { TagModule } from 'primeng/tag';
import { RatingModule } from 'primeng/rating';
import { DialogModule } from 'primeng/dialog';
import { InputTextModule } from 'primeng/inputtext';
import { TextareaModule } from 'primeng/textarea';
import { TooltipModule } from 'primeng/tooltip';
import { AccordionModule } from 'primeng/accordion';
import { CardModule } from 'primeng/card';
import { TimelineModule } from 'primeng/timeline';
import { ProgressSpinnerModule } from 'primeng/progressspinner';
import { AuthDataService } from '../../../../core/services/auth-data.service';
import { IdName } from '../../../../api';
import { DEFAULT_SYSTEM_ID } from '../../../../core/models';

@Component({
  selector: 'app-app-detail',
  standalone: true,
  imports: [
    CommonModule,
    RouterModule,
    FormsModule,
    ButtonModule,
    TagModule,
    RatingModule,
    DialogModule,
    InputTextModule,
    TextareaModule,
    TooltipModule,
    AccordionModule,
    CardModule,
    TimelineModule,
    ProgressSpinnerModule,
  ],
  templateUrl: './app-detail.component.html',
  styleUrls: ['./app-detail.component.scss'],
})
export class AppDetailComponent {
  app$: Observable<AppDefinition | null | undefined>;
  reviews$: Observable<AppReview[]> | undefined;
  loading = false;
  error: string | null = null;

  isSubmittingReview = false;
  reviewError: string | null = null;

  isSubmittingApproval = false;
  approvalError: string | null = null;

  // Review Form
  showReviewModal = false;
  targetAppId: string | null = null;
  newReviewRating = 5;
  newReviewTitle = '';
  newReviewComment = '';

  private readonly route = inject(ActivatedRoute);
  private readonly router = inject(Router);
  private readonly appStoreService = inject(AppStoreService);
  private readonly reviewService = inject(ReviewService);
  private readonly authDataService = inject(AuthDataService);

  readonly currentUserId = this.authDataService.getUserProfile()?.id;
  readonly isAdmin = this.authDataService
    .getUserProfile()
    ?.roles?.some((role: IdName) => role.id === DEFAULT_SYSTEM_ID);

  constructor() {
    this.app$ = this.route.paramMap.pipe(
      switchMap((params) => {
        const id = params.get('id');
        if (id === null || id === undefined) {
          this.loading = false;
          this.error = 'App not found.';
          return of(null);
        }

        this.loading = true;
        this.error = null;
        this.reviews$ = this.reviewService.getReviewsForApp(id);

        return this.appStoreService.getAppById(id).pipe(
          tap(() => {
            this.loading = false;
          }),
          catchError(() => {
            this.loading = false;
            this.error = 'Unable to load app details. Please try again.';
            return of(null);
          }),
        );
      }),
      shareReplay(1),
    );
  }

  openReviewModal(appId: string) {
    this.targetAppId = appId;
    this.showReviewModal = true;
  }

  closeReviewModal() {
    this.showReviewModal = false;
    this.targetAppId = null;
    this.resetReviewForm();
  }

  submitReview() {
    if (this.targetAppId === null) return;

    const title = this.newReviewTitle.trim();
    const comment = this.newReviewComment.trim();

    if (!title || !comment || this.newReviewRating < 1) {
      this.reviewError = 'Please provide a title, comment, and rating.';
      return;
    }

    this.reviewError = null;
    this.isSubmittingReview = true;

    this.reviewService
      .addReview(this.targetAppId, {
        userId: 'current-user',
        userName: 'Current User',
        organizationName: 'My Org',
        rating: this.newReviewRating,
        title,
        comment,
        isVerifiedPurchase: true,
      })
      .pipe(
        tap(() => {
          if (this.targetAppId !== null) {
            this.reviews$ = this.reviewService.getReviewsForApp(
              this.targetAppId,
            );
          }
          this.closeReviewModal();
        }),
        catchError(() => {
          this.reviewError = 'Could not submit your review. Please try again.';
          return of(null);
        }),
      )
      .subscribe({
        complete: () => (this.isSubmittingReview = false),
      });
  }

  markHelpful(_reviewId: string) {
    // Placeholder - implement when API supports helpfulness tracking
  }

  resetReviewForm() {
    this.newReviewRating = 5;
    this.newReviewTitle = '';
    this.newReviewComment = '';
  }

  isApproved(app: AppDefinition | null | undefined): boolean {
    return app?.status === 'APPROVED';
  }

  canEdit(app: AppDefinition | null | undefined): boolean {
    if (!app) return false;
    // Can only edit if user is the creator AND app is in DRAFT status
    return app.userId === this.currentUserId && app.status === 'DRAFT';
  }

  statusSeverity(
    status: AppDefinition['status'],
  ): 'success' | 'info' | 'warn' | 'danger' | 'secondary' {
    if (status === 'APPROVED') return 'success';
    if (status === 'PENDING_REVIEW') return 'warn';
    if (status === 'DRAFT') return 'secondary';
    if (status === 'SUSPENDED') return 'danger';
    return 'info';
  }

  statusLabel(status: AppDefinition['status']): string {
    return status
      .toLowerCase()
      .split('_')
      .map((part) => part[0].toUpperCase() + part.slice(1))
      .join(' ');
  }

  startEdit(app: AppDefinition) {
    this.router
      .navigate(['/app-store/create'], {
        queryParams: { appId: app.id },
        state: { appToEdit: app },
      })
      .catch(() => {});
  }

  isEditDisabled(app: AppDefinition | null | undefined): boolean {
    if (!app) return true;
    return !this.canEdit(app);
  }

  getEditDisabledReason(app: AppDefinition | null | undefined): string {
    if (!app) return '';
    if (app.status === 'PENDING_REVIEW') {
      return 'Editing is disabled while under review';
    }
    if (app.status === 'APPROVED') {
      return 'Editing is disabled for approved apps';
    }
    if (app.status === 'SUSPENDED') {
      return 'Editing is disabled for suspended apps';
    }
    if (app.status === 'REJECTED') {
      return 'App was rejected. Create a new app or contact support.';
    }
    return 'You can only edit apps in draft status';
  }

  isInPendingReview(app: AppDefinition | null | undefined): boolean {
    return app?.status === 'PENDING_REVIEW';
  }

  approveApp(app: AppDefinition | null | undefined): void {
    if (!app) return;
    this.approvalError = null;
    this.isSubmittingApproval = true;

    this.appStoreService
      .approveApp(app.id)
      .pipe(
        tap(() => {
          this.approvalError = null;
        }),
        catchError(() => {
          this.approvalError = 'Could not approve this app. Please try again.';
          return of(null);
        }),
      )
      .subscribe({
        complete: () => (this.isSubmittingApproval = false),
      });
  }

  rejectApp(app: AppDefinition | null | undefined): void {
    if (!app) return;
    this.approvalError = null;
    this.isSubmittingApproval = true;

    this.appStoreService
      .rejectApp(app.id)
      .pipe(
        tap(() => {
          this.approvalError = null;
        }),
        catchError(() => {
          this.approvalError = 'Could not reject this app. Please try again.';
          return of(null);
        }),
      )
      .subscribe({
        complete: () => (this.isSubmittingApproval = false),
      });
  }

  suspendApp(app: AppDefinition | null | undefined): void {
    if (!app) return;
    this.approvalError = null;
    this.isSubmittingApproval = true;

    this.appStoreService
      .suspendApp(app.id)
      .pipe(
        tap(() => {
          this.approvalError = null;
        }),
        catchError(() => {
          this.approvalError = 'Could not suspend this app. Please try again.';
          return of(null);
        }),
      )
      .subscribe({
        complete: () => (this.isSubmittingApproval = false),
      });
  }

  submitDraftForReview(app: AppDefinition | null | undefined): void {
    if (!app?.status || app.status !== 'DRAFT') return;
    this.approvalError = null;
    this.isSubmittingApproval = true;

    this.appStoreService
      .submitForReview(app.id)
      .pipe(
        tap(() => {
          this.approvalError = null;
        }),
        catchError(() => {
          this.approvalError = 'Could not submit for review. Please try again.';
          return of(null);
        }),
      )
      .subscribe({
        complete: () => (this.isSubmittingApproval = false),
      });
  }
}
